          <th className="p-2 border">Status</th>
        </tr>
      </thead>
      <tbody>
        {orders.map(order => (
          <tr key={order.id}>
            <td className="p-2 border">{order.id}</td>
            <td className="p-2 border">{order.status}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}
